('brief_summary', 'In one sentence, what is the brief?', 'En une phrase, quel est le mandat?', 'text', '[]', 2, true),
('mission_criticality', 'How mission-critical is this?', 'À quel point est-ce critique?', 'single_choice', '[{"value":"essential","label":"Essential to operations"},{"value":"important","label":"Important but not blocking"},{"value":"exploratory","label":"Exploratory"}]', 3, true),
('budget_signal', 'What is your indicative budget range?', 'Quelle est votre fourchette budgétaire indicative?', 'single_choice', '[{"value":"under_50k","label":"Under $50,000"},{"value":"50k_150k","label":"$50,000 – $150,000"},{"value":"150k_500k","label":"$150,000 – $500,000"},{"value":"over_500k","label":"Over $500,000"}]', 4, true),
