INSERT INTO talent.internship_programs (slug, title, title_fr, program_type, duration_months, description, description_fr, learning_outcomes, is_open, application_deadline) VALUES
('engineering-internship-2026', 'Engineering Internship Programme 2026', 'Programme de Stage en Ingénierie 2026', 'internship', 3, 'A structured three-month internship for software engineering students in Ghana and West Africa.', 'Un stage structuré de trois mois pour les étudiants en génie logiciel au Ghana et en Afrique de l''Ouest.', '["Build production features in Go","Work with raw PostgreSQL at scale","Learn clean architecture","Ship code to real users"]', true, '2026-08-01');
